<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand</title>
<style>
  :root{
    --bg:#0d0f14; --panel:#161a22; --edge:#252b38; --txt:#e6e9ef; --muted:#8b93a7;
  }
  *{box-sizing:border-box;}
  html,body{height:100%;margin:0;}
  body{
    background:radial-gradient(1200px 800px at 50% -10%, #141824, var(--bg));
    color:var(--txt);
    font-family:system-ui,-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;
    display:flex; flex-direction:column; align-items:center;
    min-height:100%; padding:22px 12px 40px; gap:16px;
  }
  h1{
    font-size:20px; font-weight:650; margin:0; letter-spacing:.5px;
    color:var(--txt);
  }
  h1 span{color:var(--muted); font-weight:400; font-size:13px;}
  #sand{
    background:#05060a;
    border:1px solid var(--edge);
    border-radius:10px;
    box-shadow:0 10px 40px rgba(0,0,0,.55), inset 0 0 0 1px rgba(255,255,255,.02);
    image-rendering:pixelated;
    cursor:crosshair;
    touch-action:none;
    width:500px; height:500px; max-width:92vw; max-height:92vw;
  }
  .toolbar{
    display:flex; flex-wrap:wrap; gap:8px; justify-content:center;
    background:var(--panel); border:1px solid var(--edge);
    padding:10px; border-radius:12px; max-width:520px;
  }
  button{
    font:inherit; font-size:13px; font-weight:600;
    color:var(--txt); background:#1e2531; border:1px solid var(--edge);
    padding:8px 13px; border-radius:8px; cursor:pointer;
    display:flex; align-items:center; gap:7px;
    transition:transform .05s ease, border-color .15s, background .15s;
  }
  button:hover{border-color:#3a4considered;}
  button:hover{border-color:#42506b;}
  button:active{transform:translateY(1px);}
  button.mat.active{
    border-color:#5b7cff; background:#232c40;
    box-shadow:0 0 0 1px #5b7cff inset, 0 0 12px rgba(91,124,255,.25);
  }
  .sw{width:13px;height:13px;border-radius:3px;border:1px solid rgba(255,255,255,.18);}
  #clear{background:#2a1620;border-color:#5a2233;color:#ffbcc8;}
  #clear:hover{border-color:#8a3348;}
  .hint{color:var(--muted); font-size:12px; text-align:center; max-width:520px;}
</style>
</head>
<body>
  <h1>Falling Sand <span>— drag to paint</span></h1>
  <canvas id="sand" width="500" height="500"></canvas>
  <div class="toolbar">
    <button class="mat active" id="mat-sand"><span class="sw" style="background:#d4b16a"></span>Sand</button>
    <button class="mat" id="mat-water"><span class="sw" style="background:#4a90d9"></span>Water</button>
    <button class="mat" id="mat-wall"><span class="sw" style="background:#8a8f9c"></span>Wall</button>
    <button class="mat" id="mat-acid"><span class="sw" style="background:#8dff3a"></span>Acid</button>
    <button class="mat" id="mat-empty"><span class="sw" style="background:#05060a"></span>Eraser</button>
    <button id="clear">Clear</button>
  </div>
  <div class="hint">Sand sinks through water &amp; acid · acid eats sand and walls · displaced liquid escapes around the pour.</div>

<script>
(function(){
  "use strict";

  // ---- materials ----
  const EMPTY=0, SAND=1, WATER=2, WALL=3, ACID=4;
  const NAMES = ["empty","sand","water","wall","acid"];
  const IDS = {empty:EMPTY, sand:SAND, water:WATER, wall:WALL, acid:ACID};
  const COLORS = {
    [EMPTY]:[5,6,10],
    [SAND]:[212,177,106],
    [WATER]:[74,144,217],
    [WALL]:[138,143,156],
    [ACID]:[141,255,58],
  };

  // ---- grid ----
  const W=100, H=100;
  const grid = new Uint8Array(W*H);
  const moved = new Uint8Array(W*H);
  const idx = (x,y)=> y*W + x;
  const isLiquid = c => c===WATER || c===ACID;

  // ---- deterministic RNG (so tick() is reproducible) ----
  let seed = 0x2f6b1a3d;
  function rng(){
    seed |= 0; seed = (seed + 0x6D2B79F5) | 0;
    let t = Math.imul(seed ^ (seed>>>15), 1 | seed);
    t = (t + Math.imul(t ^ (t>>>7), 61 | t)) ^ t;
    return ((t ^ (t>>>14)) >>> 0) / 4294967296;
  }

  function move(from,to,val){ grid[to]=val; grid[from]=EMPTY; moved[to]=1; }

  // Sand tries to sink into liquid below, displacing it AROUND itself
  // (never straight up through a sand column -> no anti-gravity eruption).
  function sinkSand(x,y){
    const i = idx(x,y), bi = idx(x,y+1);
    if(moved[bi]) return false;
    const liq = grid[bi];
    const d = rng()<0.5 ? 1 : -1;
    // 1) push liquid sideways at its own row
    for(const dd of [d,-d]){
      const nx=x+dd; if(nx<0||nx>=W) continue;
      const ti=idx(nx,y+1);
      if(grid[ti]===EMPTY && !moved[ti]){
        grid[ti]=liq; moved[ti]=1; grid[bi]=SAND; moved[bi]=1; grid[i]=EMPTY;
        return true;
      }
    }
    // 2) push liquid up-and-around, beside the sand
    for(const dd of [d,-d]){
      const nx=x+dd; if(nx<0||nx>=W) continue;
      const ti=idx(nx,y);
      if(grid[ti]===EMPTY && !moved[ti]){
        grid[ti]=liq; moved[ti]=1; grid[bi]=SAND; moved[bi]=1; grid[i]=EMPTY;
        return true;
      }
    }
    // 3) confined single grain: vertical swap ONLY if not part of a column,
    //    so liquid can never be pumped up a falling stream.
    const above = y>0 ? grid[idx(x,y-1)] : EMPTY;
    if(above!==SAND){
      grid[bi]=SAND; moved[bi]=1; grid[i]=liq; moved[i]=1;
      return true;
    }
    return false;
  }

  function updateSand(x,y){
    const i=idx(x,y);
    if(y+1>=H) return;               // bottom boundary
    const bi=idx(x,y+1), bc=grid[bi];
    if(bc===EMPTY && !moved[bi]){ move(i,bi,SAND); return; }
    if(isLiquid(bc)){ if(sinkSand(x,y)) return; }
    // diagonal slide into empty
    const d = rng()<0.5 ? 1 : -1;
    for(const dd of [d,-d]){
      const nx=x+dd; if(nx<0||nx>=W) continue;
      const di=idx(nx,y+1);
      if(grid[di]===EMPTY && !moved[di]){ move(i,di,SAND); return; }
    }
    // else rest
  }

  // shared liquid flow: down, diagonal-down, then horizontal. Never upward.
  function flow(x,y,self){
    const i=idx(x,y);
    if(y+1<H){
      const bi=idx(x,y+1);
      if(grid[bi]===EMPTY && !moved[bi]){ move(i,bi,self); return true; }
    }
    const d = rng()<0.5 ? 1 : -1;
    if(y+1<H){
      for(const dd of [d,-d]){
        const nx=x+dd; if(nx<0||nx>=W) continue;
        const ti=idx(nx,y+1);
        if(grid[ti]===EMPTY && !moved[ti]){ move(i,ti,self); return true; }
      }
    }
    for(const dd of [d,-d]){
      const nx=x+dd; if(nx<0||nx>=W) continue;
      const ti=idx(nx,y);
      if(grid[ti]===EMPTY && !moved[ti]){ move(i,ti,self); return true; }
    }
    return false;
  }

  function updateWater(x,y){ flow(x,y,WATER); }

  function updateAcid(x,y){
    const i=idx(x,y);
    // dissolve one sand/wall below or beside
    const nb=[[x,y+1],[x-1,y],[x+1,y]];
    for(const [nx,ny] of nb){
      if(nx<0||nx>=W||ny<0||ny>=H) continue;
      const ti=idx(nx,ny), c=grid[ti];
      if(c===SAND || c===WALL){
        grid[ti]=EMPTY; moved[ti]=1;
        if(rng()<0.4){ grid[i]=EMPTY; moved[i]=1; return; } // acid used up
        break; // one dissolve per step
      }
    }
    flow(x,y,ACID);
  }

  // ---- one simulation step (bottom-row-up: at most one cell per particle) ----
  function step(){
    moved.fill(0);
    for(let y=H-1; y>=0; y--){
      for(let x=0; x<W; x++){
        const i=idx(x,y);
        if(moved[i]) continue;
        const c=grid[i];
        if(c===SAND) updateSand(x,y);
        else if(c===WATER) updateWater(x,y);
        else if(c===ACID) updateAcid(x,y);
      }
    }
  }

  // ---- rendering ----
  const canvas = document.getElementById("sand");
  const ctx = canvas.getContext("2d");
  const off = document.createElement("canvas");
  off.width=W; off.height=H;
  const octx = off.getContext("2d");
  const img = octx.createImageData(W,H);
  const data = img.data;

  function render(){
    for(let p=0; p<grid.length; p++){
      const col = COLORS[grid[p]];
      const o = p*4;
      data[o]=col[0]; data[o+1]=col[1]; data[o+2]=col[2]; data[o+3]=255;
    }
    octx.putImageData(img,0,0);
    ctx.imageSmoothingEnabled=false;
    ctx.clearRect(0,0,canvas.width,canvas.height);
    ctx.drawImage(off,0,0,canvas.width,canvas.height);
  }

  // ---- public API ----
  window.sim = {
    w: W, h: H,
    tick(n){ n = (n|0); for(let k=0;k<n;k++) step(); },
    get(x,y){
      x|=0; y|=0;
      if(x<0||x>=W||y<0||y>=H) return "empty";
      return NAMES[grid[idx(x,y)]];
    },
    set(x,y,material){
      x|=0; y|=0;
      if(x<0||x>=W||y<0||y>=H) return;
      const id = IDS[material];
      if(id===undefined) return;
      grid[idx(x,y)] = id;
    },
    clear(){ grid.fill(EMPTY); }
  };

  // ---- UI: material selection ----
  let current = SAND;
  const matButtons = {
    "mat-sand":SAND, "mat-water":WATER, "mat-wall":WALL,
    "mat-acid":ACID, "mat-empty":EMPTY
  };
  Object.keys(matButtons).forEach(id=>{
    const btn=document.getElementById(id);
    btn.addEventListener("click", ()=>{
      current = matButtons[id];
      document.querySelectorAll(".mat").forEach(b=>b.classList.remove("active"));
      btn.classList.add("active");
    });
  });
  document.getElementById("clear").addEventListener("click", ()=> window.sim.clear());

  // ---- UI: painting ----
  let painting=false;
  const BRUSH=2; // radius in cells

  function paintAt(clientX, clientY){
    const rect = canvas.getBoundingClientRect();
    const cx = Math.floor((clientX-rect.left)/rect.width  * W);
    const cy = Math.floor((clientY-rect.top )/rect.height * H);
    for(let dy=-BRUSH; dy<=BRUSH; dy++){
      for(let dx=-BRUSH; dx<=BRUSH; dx++){
        if(dx*dx+dy*dy > BRUSH*BRUSH+1) continue;
        const x=cx+dx, y=cy+dy;
        if(x<0||x>=W||y<0||y>=H) continue;
        grid[idx(x,y)] = current;
      }
    }
  }

  canvas.addEventListener("mousedown", e=>{ painting=true; paintAt(e.clientX,e.clientY); });
  window.addEventListener("mousemove", e=>{ if(painting) paintAt(e.clientX,e.clientY); });
  window.addEventListener("mouseup", ()=> painting=false);

  canvas.addEventListener("touchstart", e=>{ painting=true; const t=e.touches[0]; paintAt(t.clientX,t.clientY); e.preventDefault(); }, {passive:false});
  canvas.addEventListener("touchmove", e=>{ if(painting){ const t=e.touches[0]; paintAt(t.clientX,t.clientY); } e.preventDefault(); }, {passive:false});
  window.addEventListener("touchend", ()=> painting=false);

  // ---- animation loop ----
  function frame(){
    step();
    render();
    requestAnimationFrame(frame);
  }
  render();
  requestAnimationFrame(frame);
})();
</script>
</body>
</html>
